import React from 'react';
import LiveTicker from '../components/LiveTicker';
import TradeModal from '../components/TradeModal';
import { useState } from 'react';

const Invest = () => {
    const [isModalOpen, setModalOpen] = useState(false);

    return (
        <div className="invest-container">
            <LiveTicker />

            <div className="invest-header">
                <h2>Yatırım Merkezi</h2>
                <p>Güvenilir liman altın, döviz ve yenilikçi kripto dünyasında işlem yapın.</p>
                <button className="primary-btn" onClick={() => setModalOpen(true)}>Hızlı İşlem</button>
            </div>

            <div className="dashboard-grid">
                <div className="dashboard-card">
                    <h3>Portföy Dağılımı</h3>
                    <p>Sanal Altın: %60</p>
                    <p>Döviz: %30</p>
                    <p>Bitcoin: %10</p>
                    <h4 className="gold-text mt-15">Toplam Değer: ₺250.000</h4>
                </div>

                <div className="dashboard-card">
                    <h3>Bekleyen Emirler</h3>
                    <div className="order-item">
                        <span>ONS Altın Alış - $2040</span>
                        <span className="gold-text">Bekliyor</span>
                    </div>
                    <div className="order-item">
                        <span>USD/TRY Satış - ₺32.60</span>
                        <span className="gold-text">Bekliyor</span>
                    </div>
                </div>
            </div>

            <TradeModal isOpen={isModalOpen} onClose={() => setModalOpen(false)} />
        </div>
    );
};

export default Invest;
